#include <bits/stdc++.h>
using namespace std;
int LIS(vector<int>& v) {
    vector<int> tail;
    for (int x : v) {
        auto it = lower_bound(tail.begin(), tail.end(), x);
        if (it == tail.end()) tail.push_back(x);
        else *it = x;
    }
    return tail.size();
}

void solve() {
    int N; cin >> N;
    vector<int> a(N);
    for (int i = 0; i < N; i++) cin >> a[i];

    int ans = 1;

    for (int start = 0; start < N; start++) {
        vector<int> cur;
        for (int i = 0; i < N; i++)
            cur.push_back(a[(start + i) % N]);
        ans = max(ans, LIS(cur));
    }

    cout << ans << '\n';
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int T;
    cin >> T;

    while (T--) {
        solve();
    }
    return 0;
}

