#include <stdio.h>

int lower_bound(int *arr, int size, int target) {
    int l = 0, r = size;
    while (l < r) {
        int mid = (l + r) / 2;
        if (arr[mid] < target)
            l = mid + 1;
        else
            r = mid;
    }
    return l;
}

int LIS(int *v, int n) {
    int tail[n];
    int size = 0;

    for (int i = 0; i < n; i++) {
        int pos = lower_bound(tail, size, v[i]);

        if (pos == size)
            tail[size++] = v[i];
        else
            tail[pos] = v[i];
    }

    return size;
}

void solve() {
    int N;
    scanf("%d", &N);

    int a[N];
    for (int i = 0; i < N; i++)
        scanf("%d", &a[i]);

    int ans = 1;

    for (int start = 0; start < N; start++) {
        int cur[N];

        for (int i = 0; i < N; i++)
            cur[i] = a[(start + i) % N];

        int lis = LIS(cur, N);
        if (lis > ans)
            ans = lis;
    }

    printf("%d\n", ans);
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        solve();
    }

    return 0;
}

