import java.io.*;
import java.util.*;

public class Main {

    static int LIS(ArrayList<Integer> v) {
        ArrayList<Integer> tail = new ArrayList<>();

        for (int x : v) {
            int pos = Collections.binarySearch(tail, x);

            if (pos < 0) pos = -(pos + 1);

            if (pos == tail.size()) {
                tail.add(x);
            } else {
                tail.set(pos, x);
            }
        }

        return tail.size();
    }

    static void solve(Scanner sc) {
        int N = sc.nextInt();
        int[] a = new int[N];

        for (int i = 0; i < N; i++) {
            a[i] = sc.nextInt();
        }

        int ans = 1;

        for (int start = 0; start < N; start++) {
            ArrayList<Integer> cur = new ArrayList<>();

            for (int i = 0; i < N; i++) {
                cur.add(a[(start + i) % N]);
            }

            ans = Math.max(ans, LIS(cur));
        }

        System.out.println(ans);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        int T = sc.nextInt();

        while (T-- > 0) {
            solve(sc);
        }
    }
}
